head.b:skin:
/* 
 * NeoMax - Premium Movie & Video Blogger Theme
 * Designed for High-Performance & Cinematic Experience
 */
:root {
    --bg-color: #080809;
    --surface-color: #121214;
    --accent-color: #ff0000;
    --accent-gradient: linear-gradient(45deg, #ff0000, #ff4d4d);
    --text-primary: #ffffff;
    --text-secondary: #94a3b8;
    --border-color: rgba(255,255,255,0.08);
    --card-shadow: 0 20px 40px rgba(0,0,0,0.6);
    --transition: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
    --radius-lg: 16px;
    --radius-md: 10px;
}

body {
    background-color: var(--bg-color);
    color: var(--text-primary);
    font-family: 'Inter', sans-serif;
    margin: 0;
    padding: 0;
    overflow-x: hidden;
    -webkit-font-smoothing: antialiased;
}

a { color: inherit; text-decoration: none; transition: var(--transition); }
img { max-width: 100%; height: auto; display: block; border-radius: var(--radius-md); }

.container { max-width: 1320px; margin: 0 auto; padding: 0 24px; }

/* Header */
header {
    height: 80px;
    background: rgba(8, 8, 9, 0.85);
    backdrop-filter: blur(12px);
    border-bottom: 1px solid var(--border-color);
    position: sticky;
    top: 0;
    z-index: 1000;
    display: flex;
    align-items: center;
}
.header-flex { display: flex; align-items: center; justify-content: space-between; width: 100%; }
.logo { font-size: 1.75rem; font-weight: 800; letter-spacing: -1px; background: var(--accent-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }

.nav-links { display: flex; gap: 32px; font-weight: 500; font-size: 0.95rem; }
.nav-links a:hover { color: #ff4d4d; }

.search-bar { position: relative; display: flex; align-items: center; }
.search-input {
    background: rgba(255,255,255,0.05);
    border: 1px solid var(--border-color);
    border-radius: 50px;
    padding: 10px 20px;
    color: white;
    width: 200px;
    transition: var(--transition);
}
.search-input:focus { width: 300px; outline: none; border-color: #ff0000; background: rgba(255,255,255,0.1); }

/* Hero Slider */
.hero { padding: 40px 0; }
.hero-inner {
    position: relative;
    height: 550px;
    border-radius: var(--radius-lg);
    overflow: hidden;
    box-shadow: var(--card-shadow);
}
.hero-img { width: 100%; height: 100%; object-fit: cover; }
.hero-overlay {
    position: absolute;
    inset: 0;
    background: linear-gradient(to top, #080809 0%, rgba(8,8,9,0.4) 60%, transparent 100%);
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    padding: 60px;
}
.hero-tag { background: var(--accent-gradient); padding: 4px 12px; border-radius: 4px; font-size: 0.75rem; font-weight: 700; text-transform: uppercase; margin-bottom: 16px; width: fit-content; }
.hero-title { font-size: 3.5rem; font-weight: 800; margin: 0 0 20px; line-height: 1; letter-spacing: -2px; }
.hero-desc { max-width: 600px; color: var(--text-secondary); margin-bottom: 30px; font-size: 1.1rem; }
.hero-actions { display: flex; gap: 16px; }
.btn { padding: 14px 32px; border-radius: 50px; font-weight: 600; cursor: pointer; transition: var(--transition); }
.btn-primary { background: var(--accent-gradient); color: white; }
.btn-primary:hover { transform: scale(1.05); box-shadow: 0 10px 20px rgba(255,0,0,0.3); }

/* Content Sections */
.section-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 32px; }
.section-title { font-size: 1.5rem; font-weight: 800; margin: 0; position: relative; padding-left: 16px; }
.section-title::before { content: ''; position: absolute; left: 0; top: 50%; transform: translateY(-50%); width: 4px; height: 24px; background: var(--accent-color); border-radius: 2px; }

.movie-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(200px, 1fr)); gap: 32px; }
.movie-item { position: relative; transition: var(--transition); }
.movie-item:hover { transform: translateY(-12px); }
.movie-poster { position: relative; aspect-ratio: 2/3; border-radius: var(--radius-md); overflow: hidden; margin-bottom: 16px; }
.movie-poster img { width: 100%; height: 100%; object-fit: cover; }
.movie-rating { position: absolute; top: 12px; right: 12px; background: rgba(0,0,0,0.7); backdrop-filter: blur(4px); padding: 4px 8px; border-radius: 6px; font-size: 0.8rem; font-weight: 700; color: #ffc107; display: flex; align-items: center; gap: 4px; }
.movie-play-btn { position: absolute; inset: 0; display: flex; align-items: center; justify-content: center; background: rgba(0,0,0,0.4); opacity: 0; transition: var(--transition); }
.movie-item:hover .movie-play-btn { opacity: 1; }
.play-icon { width: 56px; height: 56px; background: var(--accent-gradient); border-radius: 50%; display: flex; align-items: center; justify-content: center; }

.movie-name { font-size: 1rem; font-weight: 600; margin: 0 0 4px; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.movie-meta { font-size: 0.85rem; color: var(--text-secondary); }

/* Single Post Page */
.single-layout { display: grid; grid-template-columns: 1fr 340px; gap: 48px; padding: 48px 0; }
.video-player { width: 100%; aspect-ratio: 16/9; background: #000; border-radius: var(--radius-lg); overflow: hidden; margin-bottom: 32px; box-shadow: var(--card-shadow); }
.video-player iframe { width: 100%; height: 100%; border: none; }

.post-info { background: var(--surface-color); padding: 40px; border-radius: var(--radius-lg); border: 1px solid var(--border-color); }
.post-title { font-size: 2.5rem; font-weight: 800; margin: 0 0 24px; letter-spacing: -1px; }
.post-meta-strip { display: flex; gap: 24px; margin-bottom: 32px; color: var(--text-secondary); font-size: 0.9rem; }
.post-body { font-size: 1.1rem; line-height: 1.8; color: #cbd5e1; }
.post-body p { margin-bottom: 24px; }

/* Sidebar Widgets */
.widget { background: var(--surface-color); border-radius: var(--radius-lg); border: 1px solid var(--border-color); padding: 24px; margin-bottom: 32px; }
.widget-title { font-size: 1.1rem; font-weight: 700; margin-bottom: 20px; text-transform: uppercase; letter-spacing: 1px; color: var(--accent-color); }

.trending-item { display: flex; gap: 16px; margin-bottom: 20px; align-items: center; }
.trending-img { width: 70px; height: 100px; object-fit: cover; border-radius: 8px; flex-shrink: 0; }
.trending-title { font-size: 0.95rem; font-weight: 600; line-height: 1.3; }

/* Footer */
footer { background: #050506; padding: 80px 0 40px; border-top: 1px solid var(--border-color); margin-top: 80px; }
.footer-grid { display: grid; grid-template-columns: 2fr 1fr 1fr 1.5fr; gap: 60px; }
.footer-logo { font-size: 2rem; font-weight: 800; margin-bottom: 24px; display: block; }
.footer-text { color: var(--text-secondary); line-height: 1.6; margin-bottom: 32px; }
.footer-bottom { margin-top: 80px; padding-top: 40px; border-top: 1px solid var(--border-color); text-align: center; color: var(--text-secondary); font-size: 0.85rem; }

/* Responsive */
@media (max-width: 1100px) {
    .single-layout { grid-template-columns: 1fr; }
    .footer-grid { grid-template-columns: 1fr 1fr; }
}
@media (max-width: 768px) {
    .nav-links { display: none; }
    .hero-inner { height: 400px; }
    .hero-title { font-size: 2.25rem; }
    .hero-overlay { padding: 32px; }
    .post-title { font-size: 1.75rem; }
}

body.script:
// Scroll Effect for Header
window.addEventListener('scroll', () => {
    const header = document.querySelector('header');
    if (window.scrollY > 100) {
        header.style.padding = '10px 0';
        header.style.background = 'rgba(8, 8, 9, 0.98)';
    } else {
        header.style.padding = '0';
        header.style.background = 'rgba(8, 8, 9, 0.85)';
    }
});
